"use client";

/* ════════════════════════════════════════════════════════════════════════
   CustomerEquityChart — Customers Tier-1 signature instrument.

   Question it answers: "Is my customer base compounding or eroding?"
   180-day customer-equity curve (90d back, 90d ahead) with:
     • Pink solid history + dashed projection
     • A red "equity at risk" wedge between flat-hold and the declining
       projection — the honest reveal
     • 12-month-ago reference line (where you came from)
     • Today pulsing compass beacon + cream/gold value chip
     • Projection-end marker with value + "PROJECTED" label
     • Hover: crosshair + tiny tooltip with value, day-label, actual/projected,
       AND the period's net in/out flow (the cause of the move)

   Per the Chart Standard §2:
     - viewBox === pixel width via useChartSize
     - typed data, sampleEquity* exports
     - hero value readable without hover
     - 4 states
     - reduced-motion safe
   ════════════════════════════════════════════════════════════════════════ */

import { useEffect, useMemo, useRef, useState } from "react";
import { useChartSize, usePrefersReducedMotion } from "@/lib/useChartSize";

export type ChartState = "ready" | "loading" | "empty" | "error";

export interface EquityPoint {
  /** Day offset from today (negative = past) */
  day: number;
  /** Equity value in store currency units */
  value: number;
}

export interface EquityFlow {
  /** Day offset */
  day: number;
  /** Equity added this period */
  inn: number;
  /** Equity lost this period */
  out: number;
}

export interface CustomerEquityChartProps {
  hist?: EquityPoint[];
  proj?: EquityPoint[];
  flows?: EquityFlow[];
  /** Reference line for "12 months ago" */
  reference?: number;
  /** Value of the equity at risk (for the wedge label) */
  atRiskValue?: string;
  state?: ChartState;
  onTodayClick?: () => void;
}

export const sampleEquityHist: EquityPoint[] = [
  { day: -90, value: 11_000_000 },
  { day: -75, value: 11_180_000 },
  { day: -60, value: 11_420_000 },
  { day: -45, value: 11_650_000 },
  { day: -30, value: 11_920_000 },
  { day: -15, value: 12_180_000 },
  { day: 0, value: 12_400_000 },
];
export const sampleEquityProj: EquityPoint[] = [
  { day: 0, value: 12_400_000 },
  { day: 15, value: 12_440_000 },
  { day: 30, value: 12_380_000 },
  { day: 45, value: 12_260_000 },
  { day: 60, value: 12_100_000 },
  { day: 75, value: 11_980_000 },
  { day: 90, value: 11_880_000 },
];
export const sampleEquityFlows: EquityFlow[] = [
  { day: -82, inn: 1050, out: 520 },
  { day: -67, inn: 1120, out: 560 },
  { day: -52, inn: 1040, out: 600 },
  { day: -37, inn: 980, out: 640 },
  { day: -22, inn: 1010, out: 700 },
  { day: -7, inn: 940, out: 760 },
  { day: 8, inn: 860, out: 820 },
  { day: 23, inn: 800, out: 900 },
  { day: 38, inn: 760, out: 980 },
  { day: 53, inn: 720, out: 1020 },
  { day: 68, inn: 700, out: 1080 },
  { day: 83, inn: 680, out: 1120 },
];

const VBH = 400;
const PAD_L = 14;
const PAD_R = 18;
const PAD_T = 46;
const PAD_B = 38;

const MAX_V = 12_700_000;
const MIN_V = 10_900_000;

const PINK = "#D4537E";
const PINKD = "#8a2a4f";
const RED = "#d64545";
const BLUE = "#5B7CB0";
const INK2 = "#3d4047";
const INK3 = "#8a8d94";

const fmtM2 = (v: number) => `$${(v / 1_000_000).toFixed(2)}M`;
const fmtM1 = (v: number) => `$${(v / 1_000_000).toFixed(1)}M`;
const fmtKb = (k: number) =>
  k >= 1000 ? `$${(k / 1000).toFixed(2)}M` : `$${Math.round(k)}K`;

export function CustomerEquityChart({
  hist = sampleEquityHist,
  proj = sampleEquityProj,
  flows = sampleEquityFlows,
  reference = 11_500_000,
  atRiskValue = "−$520K projected",
  state = "ready",
  onTodayClick,
}: CustomerEquityChartProps) {
  const { ref, width: VBW } = useChartSize({ min: 820, fallback: 1280 });
  const reduce = usePrefersReducedMotion();
  const svgRef = useRef<SVGSVGElement | null>(null);
  const [hover, setHover] = useState<number | null>(null);
  const [drawn, setDrawn] = useState(reduce);

  useEffect(() => {
    if (reduce) {
      setDrawn(true);
      return;
    }
    const r = requestAnimationFrame(() => requestAnimationFrame(() => setDrawn(true)));
    return () => cancelAnimationFrame(r);
  }, [reduce]);

  // ─── States ───
  if (state !== "ready") {
    const message =
      state === "loading"
        ? "Loading 180 days of customer equity…"
        : state === "error"
          ? "Couldn't load equity. Check the connection."
          : "No customer data yet — connect a source to see equity.";
    return (
      <div className="finsit-chart-area">
        <div className={`finsit-state finsit-state--${state}`}>
          <span className="finsit-state-mk" />
          <p>{message}</p>
        </div>
      </div>
    );
  }

  // ─── Geometry ───
  const top = PAD_T;
  const plotBot = VBH - PAD_B;
  const plotH = plotBot - top;
  const R = VBW - PAD_R;
  const plotL = PAD_L;
  const plotW = R - plotL;

  const x = (d: number) => plotL + ((d + 90) / 180) * plotW;
  const y = (v: number) => top + (1 - (v - MIN_V) / (MAX_V - MIN_V)) * plotH;

  const hp = hist.map((p) => [x(p.day), y(p.value)] as const);
  const pp = proj.map((p) => [x(p.day), y(p.value)] as const);
  const tx = x(0);
  const ny = hp[hp.length - 1][1];
  const ey = pp[pp.length - 1][1];
  const endP = pp[pp.length - 1];

  // Wedge between current value (flat) and the declining projection — "equity at risk"
  const wedgePath =
    `M ${tx.toFixed(1)} ${ny.toFixed(1)} ` +
    pp
      .slice(1)
      .map((p) => `L ${p[0].toFixed(1)} ${p[1].toFixed(1)}`)
      .join(" ") +
    ` L ${x(90).toFixed(1)} ${ny.toFixed(1)} Z`;

  // Area under history (gradient)
  const histAreaD =
    `M ${hp[0][0].toFixed(1)} ${plotBot} ` +
    hp.map((p) => `L ${p[0].toFixed(1)} ${p[1].toFixed(1)}`).join(" ") +
    ` L ${hp[hp.length - 1][0].toFixed(1)} ${plotBot} Z`;

  const histPoints = hp.map((p) => `${p[0].toFixed(1)},${p[1].toFixed(1)}`).join(" ");
  const projPoints = pp.map((p) => `${p[0].toFixed(1)},${p[1].toFixed(1)}`).join(" ");
  const histLineLen = plotW * 1.4;

  const allPts = useMemo(() => [...hist, ...proj.slice(1)], [hist, proj]);
  const nearestFlow = (d: number): EquityFlow => {
    let best = flows[0];
    let bestD = Infinity;
    flows.forEach((f) => {
      const dd = Math.abs(f.day - d);
      if (dd < bestD) {
        bestD = dd;
        best = f;
      }
    });
    return best;
  };

  const handleMove = (e: React.MouseEvent) => {
    const svg = svgRef.current;
    if (!svg) return;
    const rb = svg.getBoundingClientRect();
    const sc = rb.width / VBW;
    const mx = (e.clientX - rb.left) / sc;
    let best = 0;
    let bestD = Infinity;
    allPts.forEach((p, i) => {
      const d = Math.abs(x(p.day) - mx);
      if (d < bestD) {
        bestD = d;
        best = i;
      }
    });
    setHover(best);
  };

  const refY = y(reference);

  return (
    <div className="finsit-chart-area" ref={ref}>
      <svg
        ref={svgRef}
        viewBox={`0 0 ${VBW} ${VBH}`}
        style={{ display: "block", width: "100%", height: VBH, overflow: "visible" }}
        onMouseMove={handleMove}
        onMouseLeave={() => setHover(null)}
      >
        <defs>
          <linearGradient id="eqArea" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor={PINK} stopOpacity={0.2} />
            <stop offset="100%" stopColor={PINK} stopOpacity={0} />
          </linearGradient>
          <linearGradient id="eqLine" x1="0" y1="0" x2="1" y2="0">
            <stop offset="0%" stopColor={PINK} />
            <stop offset="100%" stopColor={PINKD} />
          </linearGradient>
        </defs>

        {/* Y-axis gridlines */}
        {[12_500_000, 12_000_000, 11_000_000].map((v) => (
          <g key={v}>
            <line x1={plotL} y1={y(v)} x2={R} y2={y(v)} stroke="rgba(0,0,0,0.07)" strokeWidth={1} />
            <text
              x={plotL + 7}
              y={y(v) - 6}
              fontFamily="JetBrains Mono, monospace"
              fontSize={13}
              fontWeight={600}
              letterSpacing="0.02em"
              fill={INK3}
            >
              {fmtM2(v)}
            </text>
          </g>
        ))}

        {/* 12 months ago reference */}
        <line x1={plotL} y1={refY} x2={R} y2={refY} stroke={INK3} strokeWidth={1.3} strokeDasharray="6 4" opacity={0.75} />
        <text
          x={plotL + 7}
          y={refY - 6}
          fontFamily="JetBrains Mono, monospace"
          fontSize={11}
          fontWeight={600}
          letterSpacing="0.07em"
          fill={INK3}
        >
          {fmtM2(reference)}  ·  12 MONTHS AGO
        </text>

        {/* Equity-at-risk wedge */}
        <path
          d={wedgePath}
          fill="rgba(214,69,69,0.10)"
          opacity={drawn ? 1 : 0}
          style={{ transition: "opacity .6s ease 1.5s" }}
        />
        <line x1={tx} y1={ny} x2={x(90)} y2={ny} stroke={INK3} strokeWidth={1.2} strokeDasharray="2 4" opacity={0.7} />
        <text
          x={x(58)}
          y={(ny + ey) / 2 + 2}
          textAnchor="middle"
          fontFamily="JetBrains Mono, monospace"
          fontSize={10.5}
          fontWeight={700}
          letterSpacing="0.1em"
          fill={RED}
        >
          EQUITY AT RISK
        </text>
        <text
          x={x(58)}
          y={(ny + ey) / 2 + 18}
          textAnchor="middle"
          fontFamily="Inter, sans-serif"
          fontSize={13}
          fontWeight={600}
          fill={RED}
        >
          {atRiskValue}
        </text>

        {/* TODAY vertical divider */}
        <line x1={tx} y1={top - 6} x2={tx} y2={plotBot} stroke={BLUE} strokeWidth={1} strokeDasharray="3 3" opacity={0.5} />

        {/* Area under history */}
        <path
          d={histAreaD}
          fill="url(#eqArea)"
          opacity={drawn ? 1 : 0}
          style={{ transition: "opacity .6s ease 1.1s" }}
        />

        {/* Historical line (gradient, solid, draws in) */}
        <polyline
          points={histPoints}
          fill="none"
          stroke="url(#eqLine)"
          strokeWidth={3.5}
          strokeLinejoin="round"
          strokeLinecap="round"
          style={
            reduce
              ? undefined
              : {
                  strokeDasharray: histLineLen,
                  strokeDashoffset: drawn ? 0 : histLineLen,
                  transition: "stroke-dashoffset 1.25s cubic-bezier(.4,.1,.2,1) .1s",
                }
          }
        />

        {/* Projection line (dashed) */}
        <polyline
          points={projPoints}
          fill="none"
          stroke={PINK}
          strokeWidth={2.8}
          strokeDasharray="7 5"
          strokeLinejoin="round"
          strokeLinecap="round"
          opacity={drawn ? 0.7 : 0}
          style={{ transition: "opacity .5s ease 1.2s" }}
        />

        {/* History nodes + value labels (skip last — that's TODAY) */}
        {hp.map((p, i) => {
          const last = i === hp.length - 1;
          return (
            <g key={`h${i}`} opacity={drawn ? 1 : 0} style={{ transition: `opacity .4s ease ${0.9 + i * 0.05}s` }}>
              <rect
                x={p[0] - (last ? 4.5 : 3.5)}
                y={p[1] - (last ? 4.5 : 3.5)}
                width={last ? 9 : 7}
                height={last ? 9 : 7}
                rx={0.5}
                fill={last ? PINK : "#fff"}
                stroke={PINK}
                strokeWidth={1.9}
              />
              {!last && (
                <text
                  x={p[0]}
                  y={p[1] - 12}
                  textAnchor="middle"
                  fontFamily="JetBrains Mono, monospace"
                  fontSize={11}
                  fontWeight={600}
                  fill={INK2}
                >
                  {fmtM2(hist[i].value)}
                </text>
              )}
            </g>
          );
        })}

        {/* Projection nodes (skip first & last) */}
        {pp.slice(1, -1).map((p, i) => (
          <rect
            key={`p${i}`}
            x={p[0] - 3.5}
            y={p[1] - 3.5}
            width={7}
            height={7}
            rx={0.5}
            fill="#fff"
            stroke={PINK}
            strokeWidth={1.7}
            opacity={drawn ? 0.55 : 0}
            style={{ transition: `opacity .4s ease ${1.3 + i * 0.05}s` }}
          />
        ))}

        {/* Projection end marker */}
        <g opacity={drawn ? 1 : 0} style={{ transition: "opacity .6s ease 1.55s" }}>
          <rect
            x={endP[0] - 5}
            y={endP[1] - 5}
            width={10}
            height={10}
            rx={0.5}
            fill="#fff"
            stroke={PINK}
            strokeWidth={2.2}
          />
          <text
            x={endP[0] - 10}
            y={endP[1] - 8}
            textAnchor="end"
            fontFamily="JetBrains Mono, monospace"
            fontSize={12.5}
            fontWeight={700}
            fill={PINKD}
          >
            {fmtM2(proj[proj.length - 1].value)}
          </text>
          <text
            x={endP[0] - 10}
            y={endP[1] + 9}
            textAnchor="end"
            fontFamily="JetBrains Mono, monospace"
            fontSize={9.5}
            fontWeight={600}
            letterSpacing="0.08em"
            fill={RED}
          >
            PROJECTED
          </text>
        </g>

        {/* TODAY beacon — pulsing rings + value chip */}
        <g
          opacity={drawn ? 1 : 0}
          style={{ transition: "opacity .5s ease 1.2s", cursor: onTodayClick ? "pointer" : "default" }}
          onClick={onTodayClick}
        >
          {!reduce && (
            <>
              <circle cx={tx} cy={ny} r={6} fill="none" stroke={BLUE} strokeWidth={1.8}>
                <animate attributeName="r" values="6;26" dur="2.2s" repeatCount="indefinite" />
                <animate attributeName="opacity" values="0.5;0" dur="2.2s" repeatCount="indefinite" />
              </circle>
              <circle cx={tx} cy={ny} r={6} fill="none" stroke={BLUE} strokeWidth={1.8}>
                <animate attributeName="r" values="6;26" dur="2.2s" begin="1.1s" repeatCount="indefinite" />
                <animate attributeName="opacity" values="0.5;0" dur="2.2s" begin="1.1s" repeatCount="indefinite" />
              </circle>
            </>
          )}
          {/* Value chip */}
          <rect x={tx - 37} y={ny - 42} width={74} height={25} rx={3} fill="#fffdf8" stroke="rgba(184,138,42,0.85)" strokeWidth={0.9} />
          <rect x={tx - 37} y={ny - 42} width={3} height={25} rx={1} fill={BLUE} />
          <text
            x={tx + 3}
            y={ny - 24.5}
            textAnchor="middle"
            fontFamily="Inter, sans-serif"
            fontSize={14.5}
            fontWeight={700}
            fill="#15171c"
          >
            $12.40M
          </text>
        </g>

        {/* X labels */}
        {([
          [-90, "90 days ago"],
          [-45, "45 days ago"],
          [45, "+45 days"],
          [90, "+90 days"],
        ] as const).map(([d, l]) => (
          <text
            key={d}
            x={x(d)}
            y={plotBot + 22}
            textAnchor="middle"
            fontFamily="JetBrains Mono, monospace"
            fontSize={11.5}
            fontWeight={500}
            letterSpacing="0.05em"
            fill={INK3}
          >
            {l}
          </text>
        ))}
        <text
          x={tx}
          y={plotBot + 22}
          textAnchor="middle"
          fontFamily="JetBrains Mono, monospace"
          fontSize={11.5}
          fontWeight={700}
          letterSpacing="0.12em"
          fill="#15171c"
        >
          TODAY
        </text>

        {/* Gold corner brackets */}
        <g
          stroke="rgba(184,138,42,0.5)"
          strokeWidth={1.6}
          fill="none"
          opacity={drawn ? 1 : 0}
          style={{ transition: "opacity .6s ease 1.65s" }}
        >
          {[
            [plotL, top, 1, 1],
            [R, top, -1, 1],
            [plotL, plotBot, 1, -1],
            [R, plotBot, -1, -1],
          ].map(([bx, by, sx, sy], i) => (
            <path key={i} d={`M ${bx + sx * 13} ${by} L ${bx} ${by} L ${bx} ${by + sy * 13}`} />
          ))}
        </g>

        {/* Crosshair on hover */}
        {hover !== null && (
          <g>
            <line
              x1={x(allPts[hover].day)}
              y1={top}
              x2={x(allPts[hover].day)}
              y2={plotBot}
              stroke={BLUE}
              strokeWidth={1}
              strokeDasharray="3 3"
              opacity={0.7}
            />
            <rect
              x={x(allPts[hover].day) - 6.5}
              y={y(allPts[hover].value) - 6.5}
              width={13}
              height={13}
              rx={1.5}
              fill="#fff"
              stroke={BLUE}
              strokeWidth={2.4}
            />
          </g>
        )}

        {/* Mouse overlay */}
        <rect
          x={plotL}
          y={top}
          width={plotW}
          height={plotBot - top}
          fill="transparent"
          style={{ cursor: "crosshair" }}
        />
      </svg>

      {/* Tooltip — value, day-label + actual/projected, net flow line */}
      {hover !== null && (() => {
        const p = allPts[hover];
        const svgRect = svgRef.current?.getBoundingClientRect();
        if (!svgRect) return null;
        const sc = svgRect.width / VBW;
        const sx = x(p.day) * sc;
        const sy = y(p.value) * sc;
        const future = p.day > 0;
        const dayLabel = p.day === 0 ? "Today" : p.day < 0 ? `${-p.day} days ago` : `+${p.day} days`;
        const fl = nearestFlow(p.day);
        const net = fl.inn - fl.out;
        return (
          <div
            className="finsit-tip"
            style={{ display: "block", left: Math.max(70, Math.min(svgRect.width - 70, sx)), top: sy }}
          >
            <div className="tv">{fmtM2(p.value)}</div>
            <div className="td">
              {dayLabel} · {future ? "projected" : "actual"}
            </div>
            <div className="tg" style={{ color: net >= 0 ? "#7fd3b0" : "#e8a0a0" }}>
              net {net >= 0 ? "+" : "−"}
              {fmtKb(Math.abs(net))}  ·  in {fmtKb(fl.inn)} / out {fmtKb(fl.out)}
            </div>
          </div>
        );
      })()}
    </div>
  );
}
